import React, { useEffect } from 'react';
import styled from 'styled-components';
import AOS from 'aos';
import { FontAwesomeIcon } from '@fortawesome/react-fontawesome';
import { 
  faLaptopCode, 
  faCodeBranch, 
  faUsersCog, 
  faChalkboardTeacher 
} from '@fortawesome/free-solid-svg-icons';

const Section = styled.section`
  padding: 100px 10%;
  text-align: center;
  position: relative;
  overflow: hidden;

  &::before {
    content: '';
    position: absolute;
    top: 0;
    left: 0;
    right: 0;
    bottom: 0;
    z-index: 1;
  }

  @media (max-width: 768px) {
    padding: 60px 5%;
  }
`;

const Title = styled.h2`
  font-size: 2.5rem;
  color: #00FFFF;
  margin-bottom: 20px;
  position: relative;
  z-index: 2;

  &::after {
    content: '';
    display: block;
    width: 60px;
    height: 3px;
    background: linear-gradient(to right, #00FFFF, #00BFFF);
    margin: 10px auto;
  }

  @media (max-width: 768px) {
    font-size: 2rem;
  }
`;

const Cards = styled.div`
  display: flex;
  justify-content: center;
  flex-wrap: wrap;
  gap: 30px;
  margin-top: 50px;
  position: relative;
  z-index: 2;
`;

const Card = styled.div`
  width: 280px;
  padding: 30px;
  border-radius: 15px;
  background: rgba(255, 255, 255, 0.05);
  backdrop-filter: blur(10px);
  border: 1px solid rgba(255, 255, 255, 0.1);
  transition: all 0.4s ease;
  position: relative;
  overflow: hidden;

  &::before {
    content: '';
    position: absolute;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    background: linear-gradient(45deg, transparent, rgba(0, 255, 255, 0.1), transparent);
    transform: translateX(-100%);
    transition: transform 0.6s ease;
  }

  &:hover {
    transform: translateY(-10px);
    box-shadow: 0 10px 30px rgba(0, 255, 255, 0.1);
    border-color: rgba(0, 255, 255, 0.2);
  }

  &:hover::before {
    transform: translateX(100%);
  }

  .icon {
    font-size: 2.5rem;
    color: #00FFFF;
    margin-bottom: 20px;
    filter: drop-shadow(0 0 10px rgba(0, 255, 255, 0.3));
  }

  h3 {
    color: #00FFFF;
    font-size: 1.5rem;
    margin-bottom: 15px;
  }

  p {
    color: rgba(255, 255, 255, 0.8);
    line-height: 1.6;
    font-size: 1rem;
  }

  @media (max-width: 768px) {
    width: 100%;
    max-width: 300px;
  }
`;

const highlights = [
  {
    icon: faLaptopCode,
    title: "Workshops",
    description: "Hands-on learning in Web, AI, IoT & more. Master new skills with expert guidance."
  },
  {
    icon: faCodeBranch,
    title: "Hackathons",
    description: "Innovate & compete in exciting challenges. Turn ideas into reality in 48 hours."
  },
  {
    icon: faUsersCog,
    title: "Team Projects",
    description: "Build real-world solutions together. Collaborate and create impactful projects."
  },
  {
    icon: faChalkboardTeacher,
    title: "Tech Talks",
    description: "Sessions with industry experts & alumni. Learn from the best in the field."
  }
];

export const Highlights = () => {
  useEffect(() => {
    AOS.init({
      duration: 800,
      once: true
    });
  }, []);

  return (
    <Section id="highlights">
      <Title data-aos="fade-up" data-aos-duration="1000">What We Do</Title>
      <Cards>
        {highlights.map((item, index) => (
          <Card
            key={index}
            data-aos="fade-up"
            data-aos-delay={100 * (index + 1)}
            data-aos-duration="800"
          >
            <FontAwesomeIcon icon={item.icon} className="icon" />
            <h3>{item.title}</h3>
            <p>{item.description}</p>
          </Card>
        ))}
      </Cards>
    </Section>
  );
};

export default Highlights;
